import { Registry } from '../../../core/zc-registry';

export function reversehighlight_c(mouse, selectionManager) {
    let point = selectionManager.nearest;
    const eventHandler = this.chart.eventHandler || {},
        { reverseLegendHighlight, unselectedHighlight } = eventHandler;

    reverseLegendHighlight.highlight && reverseLegendHighlight.highlight(point);
    unselectedHighlight.highlight && unselectedHighlight.highlight(point);
}

Registry.setComponent('events.controllers.reversehighlight', reversehighlight_c);
